INSERT INTO `background_personality_traits` VALUES (1,1,'I idolize a particular hero of my faith, and constantly refer to that person\'s deeds and example.'),(2,1,'I can find common ground between the fiercest enemies, empathizing with them and always working toward peace.'),(3,1,'I see omens in every event and action. The gods try to speak to us, we just need to listen.'),(4,1,'Nothing can shake my optimistic attitude.'),(5,1,'I quote (or misquote) sacred texts and proverbs in almost every situation.'),(6,1,'I am tolerant (or intolerant) of other faiths and respect (or condemn) the worship of other gods.'),(7,1,'I\'ve enjoyed fine food, drink, and high society among my temple\'s elite. Rough living grates on me.'),(8,1,'I\'ve spent so long in the temple that I have little practical experience dealing with people in the outside world.');
