DROP TABLE IF EXISTS `class_level_feature`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `class_level_feature` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `progression_id` bigint NOT NULL,
  `type` enum('HP_INCREASE','SPELL_LEARN','SPELL_PREPARE','SPELL_SLOT_UPDATE','SUBCLASS_CHOICE','ASI_OR_FEAT','FIGHTING_STYLE','INVOCATION','METAMAGIC','CLASS_FEATURE') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `requires_choice` tinyint(1) NOT NULL DEFAULT '0',
  `metadata` text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  KEY `idx_class_feature_prog` (`progression_id`),
  CONSTRAINT `class_level_feature_ibfk_1` FOREIGN KEY (`progression_id`) REFERENCES `class_level_progression` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1113 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
