INSERT INTO `languages` VALUES (1,'abyssal','Abyssal','Infernal','Exotic',NULL,'Demons'),(2,'celestial','Celestial','Celestial','Exotic',NULL,'Celestials'),(3,'common','Common','Common','Standard',NULL,'Humans'),(4,'deep-speech','Deep Speech',NULL,'Exotic',NULL,'Aboleths, Cloakers'),(5,'draconic','Draconic','Draconic','Exotic','Draconic is thought to be one of the oldest languages and is often used in the study of magic. The language sounds harsh to most other creatures and includes numerous hard consonants and sibilants.','Dragons, Dragonborn'),(6,'dwarvish','Dwarvish','Dwarvish','Standard','Dwarvish is full of hard consonants and guttural sounds.','Dwarves'),(7,'elvish','Elvish','Elvish','Standard','Elvish is fluid, with subtle intonations and intricate grammar. Elven literature is rich and varied, and their songs and poems are famous among other races. Many bards learn their language so they can add Elvish ballads to their repertoires.','Elves'),(8,'giant','Giant','Dwarvish','Standard',NULL,'Ogres, Giants'),(9,'gnomish','Gnomish','Dwarvish','Standard','The Gnomish language, which uses the Dwarvish script, is renowned for its technical treatises and its catalogs of knowledge about the natural world.','Gnomes'),(10,'goblin','Goblin','Dwarvish','Standard',NULL,'Goblinoids'),(11,'halfling','Halfling','Common','Standard','The Halfling language isn\'t secret, but halflings are loath to share it with others. They write very little, so they don\'t have a rich body of literature. Their oral tradition, however, is very strong.','Halflings'),(12,'infernal','Infernal','Infernal','Exotic',NULL,'Devils'),(13,'orc','Orc','Dwarvish','Standard','Orc is a harsh, grating language with hard consonants. It has no script of its own but is written in the Dwarvish script.','Orcs'),(14,'primordial','Primordial','Dwarvish','Exotic',NULL,'Elementals'),(15,'sylvan','Sylvan','Elvish','Exotic',NULL,'Fey creatures'),(16,'undercommon','Undercommon','Elvish','Exotic',NULL,'Underdark traders');
/*!40000 ALTER TABLE `languages` ENABLE KEYS */;
UNLOCK TABLES;

